const i={T:{label:"OK",color:"positive"},W:{label:"Warning",color:"warning"},f:{label:"Failed",color:"negative"},A:{label:"Canceled",color:"grey"},R:{label:"Running",color:"info"},C:{label:"Waiting",color:"grey"},E:{label:"Error",color:"negative"}},f={F:"Full",I:"Incremental",D:"Differential"};function c(o){if(!o||o===0)return"0 B";const t=typeof o=="string"?parseFloat(o):o;if(isNaN(t))return o;const a=["B","KB","MB","GB","TB","PB"],r=Math.floor(Math.log(t)/Math.log(1024));return(t/Math.pow(1024,r)).toFixed(2)+" "+a[r]}function s(o){if(!o)return"—";const t=Date.now()-new Date(o.replace(" ","T")).getTime();if(isNaN(t))return o;const a=Math.floor(t/1e3);if(a<60)return`${a}s ago`;const r=Math.floor(a/60);if(r<60)return`${r}m ago`;const n=Math.floor(r/60);if(n<24)return`${n}h ago`;const e=Math.floor(n/24);if(e<30)return`${e}d ago`;const l=Math.floor(e/30);return l<12?`${l}mo ago`:`${Math.floor(l/12)}y ago`}function u(o){const t=typeof o=="string"?parseInt(o,10):o;if(!t||isNaN(t)||t===0)return"0 s";const a=Math.floor(t/86400),r=Math.floor(t%86400/3600),n=Math.floor(t%3600/60);return a>0?r>0?`${a}d ${r}h`:`${a}d`:r>0?n>0?`${r}h ${n}m`:`${r}h`:`${n}m`}export{f as a,u as b,c as f,i as j,s as t};
